from __future__ import annotations
from dataclasses import dataclass, field
from enum import Enum
from typing import Optional


class GateStatus(Enum):
    PENDING    = "pending"
    IN_REVIEW  = "in_review"
    APPROVED   = "approved"
    NEEDS_REVISION = "needs_revision"
    BLOCKED    = "blocked"     # safety / legal veto — requires exec escalation


@dataclass
class GateDecision:
    gate_id: str
    status: GateStatus
    reviewer: str
    blocking_issues: list[str]    # must be empty for APPROVED
    advisory_notes: list[str]     # non-blocking recommendations
    reviewed_at: Optional[str] = None   # ISO-8601 timestamp

    @property
    def is_approved(self) -> bool:
        return self.status == GateStatus.APPROVED

    @property
    def can_open_next_gate(self) -> bool:
        return self.is_approved


@dataclass
class ReviewGate:
    gate_id: str
    name: str
    reviewer_roles: list[str]
    sla_business_days: int
    decision: Optional[GateDecision] = None

    def submit_decision(self, decision: GateDecision) -> None:
        if decision.blocking_issues and decision.status == GateStatus.APPROVED:
            raise ValueError("Cannot APPROVE with unresolved blocking issues")
        self.decision = decision

    @property
    def is_open(self) -> bool:
        return self.decision is None or self.decision.status in (
            GateStatus.PENDING, GateStatus.IN_REVIEW, GateStatus.NEEDS_REVISION
        )

@dataclass
class TechReviewCriteria:
    """Automated pre-check before opening Gate 1 to a human reviewer."""
    prd: "PRDDocument"

    def blocking_issues(self) -> list[str]:
        issues = []
        if not self.prd.latency_budget:
            issues.append("Latency SLO (p95) is not defined")
        if not self.prd.eval_gate:
            issues.append("Eval gate (metric + threshold + dataset) is absent")
        if not self.prd.cost_budget:
            issues.append("Monthly cost budget is absent")
        if not self.prd.ai_capability_brief.model_id:
            issues.append("Target model / provider not specified")
        if any(d.status == "pending" for d in self.prd.data_requirements):
            issues.append("One or more data dependencies have no owner sign-off")
        return issues

    def is_ready_for_gate1(self) -> bool:
        return len(self.blocking_issues()) == 0

class SafetyReviewCriteria:
    def __init__(self, prd: "PRDDocument", fmea_output: "FMEAWorkshopOutput"):
        self.prd = prd
        self.fmea = fmea_output

    def blocking_issues(self) -> list[str]:
        issues = []
        if not self.prd.behavior_spec.refusal_policy:
            issues.append("No refusal policy in behavior spec")
        if not self.prd.guardrail_spec:
            issues.append("Guardrail spec (filter chain) is absent")
        if not self.fmea.is_sprint_ready():
            issues.append(
                f"FMEA has unresolved high-RPN items: "
                f"{[e.failure_mode for e in self.fmea.high_rpn_entries()]}"
            )
        if not self.prd.eval_scenarios.has_vulnerable_user_case():
            issues.append("No eval scenario covers vulnerable-user interaction")
        if self.prd.has_irreversible_actions and not self.prd.hitl_rules:
            issues.append(
                "Feature includes irreversible actions but has no HITL trigger rules"
            )
        return issues

    def is_safety_approved(self) -> bool:
        return len(self.blocking_issues()) == 0

from dataclasses import dataclass
from typing import Literal

Regulation = Literal["GDPR", "UK_GDPR", "CCPA", "EU_AI_ACT_HIGH_RISK",
                     "HIPAA", "FINRA", "NONE"]


@dataclass
class ComplianceRequirement:
    regulation: Regulation
    triggered: bool
    prd_section: str
    evidence_required: str   # what must appear in the PRD to satisfy this reg
    legal_sign_off: bool = False

    @property
    def is_cleared(self) -> bool:
        return not self.triggered or self.legal_sign_off


@dataclass
class LegalReviewCriteria:
    prd: "PRDDocument"
    requirements: list[ComplianceRequirement]

    def blocking_issues(self) -> list[str]:
        return [
            f"{r.regulation}: {r.evidence_required}"
            for r in self.requirements
            if r.triggered and not r.legal_sign_off
        ]

    def is_legal_approved(self) -> bool:
        return len(self.blocking_issues()) == 0

    def applicable_regulations(self) -> list[Regulation]:
        return [r.regulation for r in self.requirements if r.triggered]

from enum import Enum


class ScopeChangeType(Enum):
    NEW_DATA_SOURCE     = "new_data_source"
    AUDIENCE_EXPANDED   = "audience_expanded"
    NEW_AI_CAPABILITY   = "new_ai_capability"
    MODEL_SWAP          = "model_swap"
    LATENCY_SLO_RELAXED = "latency_slo_relaxed"

# Gates invalidated by each scope change type
INVALIDATION_MAP: dict[ScopeChangeType, list[int]] = {
    ScopeChangeType.NEW_DATA_SOURCE:     [2, 3],
    ScopeChangeType.AUDIENCE_EXPANDED:   [2, 3],
    ScopeChangeType.NEW_AI_CAPABILITY:   [1, 2, 3],
    ScopeChangeType.MODEL_SWAP:          [1, 2],
    ScopeChangeType.LATENCY_SLO_RELAXED: [1],
}


@dataclass
class ScopeChange:
    change_type: ScopeChangeType
    description: str
    detected_at: str   # ISO-8601

    @property
    def invalidated_gates(self) -> list[int]:
        return INVALIDATION_MAP[self.change_type]

    def requires_full_re_review(self) -> bool:
        return 2 in self.invalidated_gates and 3 in self.invalidated_gates


@dataclass
class PRDApprovalState:
    """Tracks live approval state across all four gates."""
    gates: list[ReviewGate]          # ordered Gate 1 → 4
    scope_changes: list[ScopeChange] = field(default_factory=list)

    def current_valid_approvals(self) -> set[int]:
        """Returns gate numbers that are still APPROVED (not invalidated)."""
        invalidated = {
            g for sc in self.scope_changes for g in sc.invalidated_gates
        }
        return {
            i + 1
            for i, gate in enumerate(self.gates)
            if gate.decision and gate.decision.is_approved
            and (i + 1) not in invalidated
        }

    def is_final_approved(self) -> bool:
        return self.current_valid_approvals() == {1, 2, 3, 4}

    def next_required_action(self) -> str:
        valid = self.current_valid_approvals()
        for gate_num in [1, 2, 3, 4]:
            if gate_num not in valid:
                gate = self.gates[gate_num - 1]
                return f"Gate {gate_num} ({gate.name}) requires {'re-' if gate.decision else ''}review"
        return "PRD is fully approved — engineering may begin"

# Example: Jira/Linear webhook handler that blocks sprint planning
# when the PRD has not reached final approval.

from dataclasses import dataclass
from typing import Any


@dataclass
class FeatureTicket:
    ticket_id: str
    prd_id: str
    prd_approval_state: PRDApprovalState

    def can_enter_sprint(self) -> tuple[bool, str]:
        if self.prd_approval_state.is_final_approved():
            return True, "PRD fully approved"
        reason = self.prd_approval_state.next_required_action()
        return False, f"Sprint entry blocked: {reason}"

    def sprint_ready_label(self) -> str:
        ok, msg = self.can_enter_sprint()
        return "prd:approved" if ok else "prd:blocked"


def on_sprint_planning_event(ticket: FeatureTicket, event: dict[str, Any]) -> dict:
    """Webhook handler called when a ticket is dragged into a sprint."""
    can_enter, reason = ticket.can_enter_sprint()
    if not can_enter:
        return {
            "action": "reject",
            "ticket_id": ticket.ticket_id,
            "reason": reason,
            "label": ticket.sprint_ready_label(),
        }
    return {"action": "accept", "ticket_id": ticket.ticket_id}
